refsection.programlisting:
//Nichols chart
clf()
subplot(1,2,1)
nicholschart();
subplot(1,2,2)
mod = [-35:5:-10 -6 -3 -1 -0.2 1 2 3 6];
nicholschart(mod, -[1 20 40 80 160 180],["khaki" "paleturquoise"]);

